date_default_timezone_set('Asia/Kolkata');
$today = date("d-m-Y");
//=====================================================================
// STEP 1: PARSE free-game.txt (MULTILINE FORMAT)
//=====================================================================
$freeGameData = array();
$currentMarket = "";
$lineStep = 0;
foreach ($freeGame as $line) {
    $line = trim($line);
    if ($line == "" || $line == "-----------") continue;
    if (strpos($line, "/") !== false && strlen($line) == 10) {
        continue; // DATE LINE -> ignore
    }
    // Market name line
    if ($lineStep == 0) {
        $currentMarket = $line;
        $freeGameData[$currentMarket] = array(
            "single" => array(),
            "panna" => array(),
            "jodi" => array()
        );
        $lineStep = 1;
        continue;
    }
    // Single digits line (e.g. 1-6-3-8)
    if ($lineStep == 1) {
        $freeGameData[$currentMarket]["single"] = explode("-", $line);
        $lineStep = 2;
        continue;
    }
    // Panna line (e.g. 227-367-139-189-558)
    if ($lineStep == 2) {
        $freeGameData[$currentMarket]["panna"] = explode("-", $line);
        $lineStep = 3;
        continue;
    }
    // Jodi line (e.g. 13-18-63-68-31-36-81-86)
    if ($lineStep == 3) {
        $freeGameData[$currentMarket]["jodi"] = explode("-", $line);
        $lineStep = 0; // reset for next market
        continue;
    }
}
//=====================================================================
// STEP 2: PARSE other-free-game.txt (Single-line Format)
//=====================================================================
foreach ($theData33 as $line) {
    $line = trim($line);
    if ($line == "") continue;
    list($mName, $sing, $panna, $jodi, $junk) = explode("|", $line);
    if (!isset($freeGameData[$mName])) {
        $freeGameData[$mName] = array(
            "single" => array(),
            "panna" => array(),
            "jodi" => array()
        );
    }
    if ($sing != "") $freeGameData[$mName]["single"] = explode("-", trim($sing, "-"));
    if ($panna != "") $freeGameData[$mName]["panna"] = explode("-", trim($panna, "-"));
    if ($jodi != "") $freeGameData[$mName]["jodi"] = explode("-", trim($jodi, "-"));
}
//=====================================================================
// STEP 3: READ TODAY'S RESULT FROM xzavierJoaquinosia.txt
//=====================================================================
$finalFreeGameMatch = array();
foreach ($theData as $line) {
    $line = trim($line);
    if ($line == "") continue;
    list($order, $gameName, $gameResult, $timeOpen, $timeClose, $gameBgcolor,
         $gameFontcolor, $gameLinecolor, $frequency, $liveTimeBefore,
         $liveTimeAfter, $updateDate, $status, $expiryDate, $jodiLink,
         $panelLink, $temp_last_updated_result, $finalAnk)
        = explode("|", $line);
    if ($updateDate != $today) {
        continue; // not today's result
    }
    // Clean result
    $tmp = str_replace("-", "", $gameResult);
    if (!is_numeric($tmp)) continue;
    $resultParts = explode("-", $gameResult);
    $result_panna_open = $resultParts[0];
    $result_jodi_tmp = $resultParts[1];
    $result_panna_close = $resultParts[2];
    $result_ank_open = substr($result_jodi_tmp, 0, 1);
    $result_ank_close = substr($result_jodi_tmp, 1, 1);
    if (strlen($result_jodi_tmp) == 2) {
        $result_jodi = $result_jodi_tmp;
    } else {
        $result_jodi = "";
    }
    // If free game exists
    if (isset($freeGameData[$gameName])) {
        $sg = $freeGameData[$gameName]["single"];
        $pn = $freeGameData[$gameName]["panna"];
        $jd = $freeGameData[$gameName]["jodi"];
        $matchSingleOpen = in_array($result_ank_open, $sg) ? "PASS" : "FAIL";
        $matchSingleClose = in_array($result_ank_close, $sg) ? "PASS" : "FAIL";
        $matchJodi = ($result_jodi != "" && in_array($result_jodi, $jd)) ? "PASS" : "FAIL";
        $matchPannaOpen = in_array($result_panna_open, $pn) ? "PASS" : "FAIL";
        $matchPannaClose = in_array($result_panna_close, $pn) ? "PASS" : "FAIL";
        $finalFreeGameMatch[$gameName] = array(
            "open_single" => $matchSingleOpen,
            "open_ank" => $result_ank_open,
            "close_single" => $matchSingleClose,
            "close_ank" => $result_ank_close,
            "jodi" => $matchJodi,
            "jodi_value" => $result_jodi,
            "panna_open" => $matchPannaOpen,
            "panna_open_value" => $result_panna_open,
            "panna_close" => $matchPannaClose,
            "panna_close_value" => $result_panna_close
        );
    }
}
//=====================================================================
// STEP 4: DISPLAY RESULT WHEREVER YOU WANT IN index.php
//=====================================================================
echo "<span class='hd1'>AAJ KYA PASS HUA</span>";
